fn canonical_message_folder_id(email: &JmapEmail, mailboxes: &[JmapMailbox]) -> u64 {
    email
        .mailbox_states
        .iter()
        .find_map(|state| {
            mailboxes
                .iter()
                .find(|mailbox| mailbox.id == state.mailbox_id)
                .map(mapi_folder_id)
        })
        .or_else(|| {
            mailboxes
                .iter()
                .find(|mailbox| mailbox.id == email.mailbox_id)
                .map(mapi_folder_id)
        })
        .unwrap_or_else(|| {
            mailboxes
                .iter()
                .find(|mailbox| mailbox.role == email.mailbox_role)
                .map(mapi_folder_id)
                .unwrap_or(INBOX_FOLDER_ID)
        })
}

fn fallback_open_message_folder_id(
    requested_folder_id: u64,
    email: &JmapEmail,
    mailboxes: &[JmapMailbox],
) -> u64 {
    if email_matches_folder(email, requested_folder_id, mailboxes) {
        requested_folder_id
    } else {
        canonical_message_folder_id(email, mailboxes)
    }
}

fn open_message_folder_id(request: &RopRequest, message_id: u64) -> u64 {
    request.folder_id().unwrap_or_else(|| {
        if crate::mapi_store::is_outlook_local_freebusy_message_id(message_id) {
            FREEBUSY_DATA_FOLDER_ID
        } else {
            INBOX_FOLDER_ID
        }
    })
}

fn unique_message_for_id<'a>(message_id: u64, emails: &'a [JmapEmail]) -> Option<&'a JmapEmail> {
    let mut matches = emails
        .iter()
        .filter(|email| mapi_item_id_matches(&email.id, message_id));
    let email = matches.next()?;
    matches.next().is_none().then_some(email)
}

fn persisted_message_delete_is_best_effort(object: Option<&MapiObject>) -> bool {
    matches!(object, Some(MapiObject::Message { .. }))
}

fn append_save_changes_message_response(
    responses: &mut Vec<u8>,
    handle_slots: &mut Vec<u32>,
    request: &RopRequest,
    handle: u32,
    message_id: u64,
) {
    set_handle_slot(handle_slots, Some(request.response_handle_index()), handle);
    responses.extend_from_slice(&rop_save_changes_message_response(request, message_id));
}

fn private_logon_request_handle(
    session: &MapiSession,
    handle_slots: &[u32],
    request: &RopRequest,
) -> bool {
    let object = input_object(session, handle_slots, request);
    matches!(object, Some(MapiObject::Logon))
        || (object.is_none()
            && request.input_handle_index() == Some(0)
            && input_handle(handle_slots, request).is_some())
}

fn logon_request_handle(session: &MapiSession, handle_slots: &[u32], request: &RopRequest) -> bool {
    private_logon_request_handle(session, handle_slots, request)
        || matches!(
            input_object(session, handle_slots, request),
            Some(MapiObject::PublicFolderLogon)
        )
}

#[derive(Debug)]
struct BoundedSearchCriteria {
    scope_json: Value,
    restriction_json: Value,
}

struct BoundedRuleMutation {
    name: String,
    content: String,
    active: bool,
}

fn bounded_rule_mutation_from_row(row: &ModifyRulesRow) -> Result<BoundedRuleMutation, u32> {
    if row
        .properties
        .keys()
        .any(|tag| matches!(*tag, 0x6679_00FD | 0x6680_00FE))
    {
        return Err(EC_RULE_UNSUPPORTED);
    }
    let name = row
        .properties
        .get(&PID_TAG_RULE_NAME_W)
        .and_then(|value| value.clone().into_text())
        .map(|value| value.trim().to_string())
        .filter(|value| !value.is_empty())
        .ok_or(EC_RULE_INVALID_PARAMETER)?;
    let active = row
        .properties
        .get(&PID_TAG_RULE_STATE)
        .and_then(MapiValue::as_i64)
        .map(|value| value as u32 & ST_ENABLED != 0)
        .unwrap_or(true);
    let provider_data = row
        .properties
        .get(&PID_TAG_RULE_PROVIDER_DATA)
        .and_then(|value| match value {
            MapiValue::Binary(bytes) => serde_json::from_slice::<Value>(bytes).ok(),
            _ => None,
        })
        .ok_or(EC_RULE_UNSUPPORTED)?;
    let content = bounded_rule_sieve_from_json(&provider_data)?;
    Ok(BoundedRuleMutation {
        name,
        content,
        active,
    })
}

fn bounded_rule_sieve_from_json(value: &Value) -> Result<String, u32> {
    if value
        .get("clientOnly")
        .and_then(Value::as_bool)
        .unwrap_or(false)
        || value
            .get("delegate")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        || value.get("delegateTemplate").is_some()
        || value
            .get("deferredAction")
            .and_then(Value::as_bool)
            .unwrap_or(false)
        || value.get("exchangeBlob").is_some()
    {
        return Err(EC_RULE_UNSUPPORTED);
    }
    let condition = value.get("condition").unwrap_or(&Value::Null);
    let test = match condition
        .get("kind")
        .and_then(Value::as_str)
        .unwrap_or("always")
    {
        "always" => "true".to_string(),
        "subjectContains" => format!(
            r#"header :contains "Subject" "{}""#,
            sieve_escape(
                condition
                    .get("value")
                    .and_then(Value::as_str)
                    .ok_or(EC_RULE_INVALID_PARAMETER)?
            )
        ),
        "fromContains" => format!(
            r#"address :contains "From" "{}""#,
            sieve_escape(
                condition
                    .get("value")
                    .and_then(Value::as_str)
                    .ok_or(EC_RULE_INVALID_PARAMETER)?
            )
        ),
        _ => return Err(EC_RULE_UNSUPPORTED),
    };
    let mut requirements = Vec::new();
    let mut actions = Vec::new();
    for action in value
        .get("actions")
        .and_then(Value::as_array)
        .ok_or(EC_RULE_INVALID_PARAMETER)?
    {
        match action.get("type").and_then(Value::as_str) {
            Some("move") => {
                requirements.push("fileinto");
                actions.push(format!(
                    r#"fileinto "{}";"#,
                    sieve_escape(
                        action
                            .get("folder")
                            .and_then(Value::as_str)
                            .ok_or(EC_RULE_INVALID_PARAMETER)?
                    )
                ));
            }
            Some("delete") => actions.push("discard;".to_string()),
            Some("forward") | Some("redirect") => {
                requirements.push("redirect");
                actions.push(format!(
                    r#"redirect "{}";"#,
                    sieve_escape(
                        action
                            .get("address")
                            .and_then(Value::as_str)
                            .ok_or(EC_RULE_INVALID_PARAMETER)?
                    )
                ));
            }
            Some("markRead") => actions.push("keep;".to_string()),
            _ => return Err(EC_RULE_UNSUPPORTED),
        }
    }
    if value
        .get("stopProcessing")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        actions.push("stop;".to_string());
    }
    if actions.is_empty() {
        return Err(EC_RULE_INVALID_PARAMETER);
    }
    requirements.sort_unstable();
    requirements.dedup();
    let require = if requirements.is_empty() {
        String::new()
    } else {
        format!(
            "require [{}];\n",
            requirements
                .iter()
                .map(|requirement| format!(r#""{requirement}""#))
                .collect::<Vec<_>>()
                .join(", ")
        )
    };
    Ok(format!(
        "{require}if {test} {{\n    {}\n}}",
        actions.join("\n    ")
    ))
}

fn sieve_escape(value: &str) -> String {
    value.replace('\\', "\\\\").replace('"', "\\\"")
}

fn rule_audit(principal: &AccountPrincipal, action: &str, subject: &str) -> AuditEntryInput {
    AuditEntryInput {
        actor: principal.email.clone(),
        action: action.to_string(),
        subject: subject.to_string(),
    }
}

const PUBLIC_FOLDER_PER_USER_STREAM_MAGIC: &[u8; 8] = b"LPEPFU1\0";

fn public_folder_per_user_stream(states: &[PublicFolderPerUserState]) -> Vec<u8> {
    let mut states = states.to_vec();
    states.sort_by(|left, right| left.item_id.cmp(&right.item_id));
    let mut stream = Vec::new();
    stream.extend_from_slice(PUBLIC_FOLDER_PER_USER_STREAM_MAGIC);
    stream.extend_from_slice(&(states.len().min(u16::MAX as usize) as u16).to_le_bytes());
    for state in states.into_iter().take(u16::MAX as usize) {
        stream.extend_from_slice(state.item_id.as_bytes());
        stream.push(state.is_read as u8);
        stream.extend_from_slice(&state.last_seen_change.to_le_bytes());
    }
    stream
}

fn public_folder_per_user_patches(data: &[u8]) -> Option<Vec<PublicFolderPerUserStatePatch>> {
    if data.is_empty() {
        return Some(Vec::new());
    }
    if data.len() < PUBLIC_FOLDER_PER_USER_STREAM_MAGIC.len() + 2
        || &data[..PUBLIC_FOLDER_PER_USER_STREAM_MAGIC.len()]
            != PUBLIC_FOLDER_PER_USER_STREAM_MAGIC.as_slice()
    {
        return None;
    }
    let mut offset = PUBLIC_FOLDER_PER_USER_STREAM_MAGIC.len();
    let count = u16::from_le_bytes(data.get(offset..offset + 2)?.try_into().ok()?) as usize;
    offset += 2;
    let mut patches = Vec::with_capacity(count);
    for _ in 0..count {
        let item_id = uuid::Uuid::from_slice(data.get(offset..offset + 16)?).ok()?;
        offset += 16;
        let is_read = *data.get(offset)? != 0;
        offset += 1;
        let last_seen_change = i64::from_le_bytes(data.get(offset..offset + 8)?.try_into().ok()?);
        offset += 8;
        patches.push(PublicFolderPerUserStatePatch {
            item_id,
            is_read,
            last_seen_change: Some(last_seen_change),
            private_json: None,
        });
    }
    (offset == data.len()).then_some(patches)
}

fn bounded_search_criteria_from_rop(
    request: &RopRequest,
    search_folder_id: u64,
    previous_definition: Option<&SearchFolderDefinition>,
    mailboxes: &[JmapMailbox],
) -> Result<BoundedSearchCriteria, u32> {
    let restriction_bytes = request
        .search_criteria_restriction_bytes()
        .ok_or(EC_SEARCH_INVALID_PARAMETER)?;
    let restriction = if restriction_bytes.is_empty() {
        None
    } else {
        Some(parse_mapi_restriction(restriction_bytes).map_err(|_| EC_SEARCH_UNSUPPORTED)?)
    };
    let folder_ids = request
        .search_criteria_folder_ids()
        .ok_or(EC_SEARCH_INVALID_PARAMETER)?;
    let flags = request
        .search_criteria_flags()
        .ok_or(EC_SEARCH_INVALID_PARAMETER)?;
    if !set_search_criteria_flags_are_valid(flags) {
        return Err(EC_SEARCH_INVALID_PARAMETER);
    }

    let restriction_json = if let Some(restriction) = restriction {
        if microsoft_oxcdata_reminders_restriction(&restriction) {
            json!({
                "kind": "exchange_reminders",
                "match": "reminder_set_or_recurring",
                "recurrenceHorizonDays": 90,
                "occurrenceDismissals": true
            })
        } else {
            let clauses = bounded_search_restriction_clauses(&restriction)?;
            if clauses.is_empty() {
                return Err(EC_SEARCH_INVALID_PARAMETER);
            }
            json!({
                "kind": "mapi_bounded",
                "all": clauses
            })
        }
    } else {
        previous_mapi_bounded_restriction_json(previous_definition)
            .ok_or(EC_SEARCH_NOT_INITIALIZED)?
    };

    let scope_json = if folder_ids.is_empty() {
        let mut scope = previous_mapi_bounded_scope_json(previous_definition)
            .ok_or(EC_SEARCH_NOT_INITIALIZED)?;
        if let Some(scope) = scope.as_object_mut() {
            scope.insert(
                "recursive".to_string(),
                Value::Bool(flags & SEARCH_RECURSIVE_FLAG != 0),
            );
        }
        scope
    } else {
        let mut canonical_folder_ids = Vec::new();
        let mut folder_roles = Vec::new();
        for folder_id in folder_ids {
            if folder_id == search_folder_id {
                return Err(EC_SEARCH_SCOPE_VIOLATION);
            }
            if let Some(mailbox) = folder_row_for_id(folder_id, mailboxes) {
                canonical_folder_ids.push(mailbox.id.to_string());
                if !mailbox.role.is_empty() {
                    folder_roles.push(mailbox.role.clone());
                }
            } else if let Some(role) = role_for_folder_id(folder_id) {
                folder_roles.push(role.to_string());
            } else {
                return Err(EC_SEARCH_NOT_FOUND);
            }
        }
        folder_roles.sort();
        folder_roles.dedup();
        json!({
            "kind": "mapi_bounded",
            "scope": "folders",
            "recursive": flags & SEARCH_RECURSIVE_FLAG != 0,
            "folderIds": canonical_folder_ids,
            "folderRoles": folder_roles
        })
    };
    Ok(BoundedSearchCriteria {
        scope_json,
        restriction_json,
    })
}

fn previous_mapi_bounded_restriction_json(
    definition: Option<&SearchFolderDefinition>,
) -> Option<Value> {
    let restriction = &definition?.restriction_json;
    if restriction.get("kind").and_then(Value::as_str) != Some("mapi_bounded")
        || restriction
            .get("all")
            .and_then(Value::as_array)
            .is_none_or(Vec::is_empty)
    {
        return None;
    }
    Some(restriction.clone())
}

fn previous_mapi_bounded_scope_json(definition: Option<&SearchFolderDefinition>) -> Option<Value> {
    let scope = &definition?.scope_json;
    if scope.get("kind").and_then(Value::as_str) != Some("mapi_bounded")
        || (scope
            .get("folderIds")
            .and_then(Value::as_array)
            .is_none_or(Vec::is_empty)
            && scope
                .get("folderRoles")
                .and_then(Value::as_array)
                .is_none_or(Vec::is_empty))
    {
        return None;
    }
    Some(scope.clone())
}

fn set_search_criteria_flags_are_valid(flags: u32) -> bool {
    flags & !SET_SEARCH_VALID_FLAGS == 0
        && flags & (SET_SEARCH_STOP_FLAG | SET_SEARCH_RESTART_FLAG)
            != (SET_SEARCH_STOP_FLAG | SET_SEARCH_RESTART_FLAG)
        && flags & (SEARCH_RECURSIVE_FLAG | SET_SEARCH_SHALLOW_FLAG)
            != (SEARCH_RECURSIVE_FLAG | SET_SEARCH_SHALLOW_FLAG)
        && flags & (SET_SEARCH_CONTENT_INDEXED_FLAG | SET_SEARCH_NON_CONTENT_INDEXED_FLAG)
            != (SET_SEARCH_CONTENT_INDEXED_FLAG | SET_SEARCH_NON_CONTENT_INDEXED_FLAG)
}

fn bounded_search_restriction_clauses(restriction: &MapiRestriction) -> Result<Vec<Value>, u32> {
    match restriction {
        MapiRestriction::InvalidTableRestriction => Err(EC_SEARCH_UNSUPPORTED),
        MapiRestriction::And(children) => {
            let mut clauses = Vec::new();
            for child in children {
                clauses.extend(bounded_search_restriction_clauses(child)?);
            }
            Ok(clauses)
        }
        MapiRestriction::Content {
            property_tag,
            value,
            fuzzy_level_low,
            ..
        } => bounded_search_content_clause(*property_tag, value, *fuzzy_level_low)
            .map(|clause| vec![clause]),
        MapiRestriction::Not(child) => bounded_search_not_clause(child).map(|clause| vec![clause]),
        MapiRestriction::Property {
            relop,
            property_tag,
            value,
        } => {
            bounded_search_property_clause(*relop, *property_tag, value).map(|clause| vec![clause])
        }
        MapiRestriction::Bitmask {
            property_tag,
            mask,
            must_be_nonzero,
        } if *property_tag == PID_TAG_MESSAGE_FLAGS && *mask == MSGFLAG_READ => Ok(vec![json!({
            "field": "unread",
            "equals": !*must_be_nonzero
        })]),
        MapiRestriction::Exist { property_tag }
            if canonical_property_storage_tag(*property_tag) == PID_TAG_HAS_ATTACHMENTS =>
        {
            Ok(vec![json!({
                "field": "hasAttachment",
                "equals": true
            })])
        }
        _ => Err(EC_SEARCH_UNSUPPORTED),
    }
}

fn microsoft_oxcdata_reminders_restriction(restriction: &MapiRestriction) -> bool {
    match restriction {
        MapiRestriction::And(children) => {
            children
                .iter()
                .any(microsoft_oxcdata_excluded_parent_folders_restriction)
                && children
                    .iter()
                    .any(microsoft_oxcdata_reminder_core_restriction)
        }
        _ => microsoft_oxcdata_reminder_core_restriction(restriction),
    }
}

fn microsoft_oxcdata_excluded_parent_folders_restriction(restriction: &MapiRestriction) -> bool {
    match restriction {
        MapiRestriction::And(children) if children.len() >= 4 => children.iter().all(|child| {
            matches!(
                child,
                MapiRestriction::Property {
                    relop: 0x05,
                    property_tag,
                    value: MapiValue::Binary(_),
                } if canonical_property_storage_tag(*property_tag) == PID_TAG_PARENT_ENTRY_ID
            )
        }),
        _ => false,
    }
}

fn microsoft_oxcdata_reminder_core_restriction(restriction: &MapiRestriction) -> bool {
    const MSGFLAG_SUBMIT: u32 = 0x0000_0004;

    let MapiRestriction::And(children) = restriction else {
        return false;
    };

    children
        .iter()
        .any(microsoft_oxcdata_not_schedule_message_class)
        && children.iter().any(|child| {
            matches!(
                child,
                MapiRestriction::Bitmask {
                    property_tag,
                    mask: MSGFLAG_SUBMIT,
                    must_be_nonzero: false,
                } if canonical_property_storage_tag(*property_tag) == PID_TAG_MESSAGE_FLAGS
            )
        })
        && children.iter().any(microsoft_oxcdata_reminder_or_recurring)
}

fn microsoft_oxcdata_not_schedule_message_class(restriction: &MapiRestriction) -> bool {
    let MapiRestriction::Not(child) = restriction else {
        return false;
    };
    let MapiRestriction::And(children) = child.as_ref() else {
        return false;
    };
    children.iter().any(|child| {
        matches!(
            child,
            MapiRestriction::Exist { property_tag }
                if canonical_property_storage_tag(*property_tag) == PID_TAG_MESSAGE_CLASS_W
        )
    }) && children.iter().any(|child| {
        matches!(
            child,
            MapiRestriction::Content {
                property_tag,
                value,
                fuzzy_level_low: 0x0002,
                ..
            } if canonical_property_storage_tag(*property_tag) == PID_TAG_MESSAGE_CLASS_W
                && value.eq_ignore_ascii_case("IPM.Schedule")
        )
    })
}

fn microsoft_oxcdata_reminder_or_recurring(restriction: &MapiRestriction) -> bool {
    let MapiRestriction::Or(children) = restriction else {
        return false;
    };

    children
        .iter()
        .any(microsoft_oxcdata_reminder_set_true_property)
        && children
            .iter()
            .any(microsoft_oxcdata_recurring_exists_and_true)
}

fn microsoft_oxcdata_reminder_set_true_property(restriction: &MapiRestriction) -> bool {
    matches!(
        restriction,
        MapiRestriction::Property {
            relop: 0x04,
            property_tag,
            value: MapiValue::Bool(true),
        } if canonical_property_storage_tag(*property_tag) == PID_LID_REMINDER_SET_TAG
    )
}

fn microsoft_oxcdata_recurring_exists_and_true(restriction: &MapiRestriction) -> bool {
    let MapiRestriction::And(children) = restriction else {
        return false;
    };
    children.iter().any(|child| {
        matches!(
            child,
            MapiRestriction::Exist { property_tag }
                if canonical_property_storage_tag(*property_tag) == PID_LID_RECURRING_TAG
        )
    }) && children.iter().any(|child| {
        matches!(
            child,
            MapiRestriction::Property {
                relop: 0x04,
                property_tag,
                value: MapiValue::Bool(true),
            } if canonical_property_storage_tag(*property_tag) == PID_LID_RECURRING_TAG
        )
    })
}

fn bounded_search_content_clause(
    property_tag: u32,
    value: &str,
    fuzzy_level_low: u16,
) -> Result<Value, u32> {
    let field = match canonical_property_storage_tag(property_tag) {
        PID_TAG_SUBJECT_W | PID_TAG_NORMALIZED_SUBJECT_W => "subject",
        PID_TAG_BODY_W | PID_TAG_BODY_STRING8 | PID_TAG_BODY_HTML_W => "body",
        PID_TAG_SENDER_NAME_W | PID_TAG_SENDER_EMAIL_ADDRESS_W => "sender",
        _ => return Err(EC_SEARCH_UNSUPPORTED),
    };
    let operator = match fuzzy_level_low {
        0x0000 => "equals",
        0x0001 => "contains",
        _ => return Err(EC_SEARCH_UNSUPPORTED),
    };
    Ok(json!({
        "field": field,
        operator: value
    }))
}

fn bounded_search_not_clause(restriction: &MapiRestriction) -> Result<Value, u32> {
    match restriction {
        MapiRestriction::Content {
            property_tag,
            value,
            fuzzy_level_low,
            ..
        } if canonical_property_storage_tag(*property_tag) == PID_TAG_MESSAGE_CLASS_W => {
            let operator = match fuzzy_level_low {
                0x0000 => "notEquals",
                0x0002 => "notPrefix",
                _ => return Err(EC_SEARCH_UNSUPPORTED),
            };
            Ok(json!({
                "field": "messageClass",
                operator: value
            }))
        }
        _ => Err(EC_SEARCH_UNSUPPORTED),
    }
}

fn bounded_search_property_clause(
    relop: u8,
    property_tag: u32,
    value: &MapiValue,
) -> Result<Value, u32> {
    match canonical_property_storage_tag(property_tag) {
        PID_TAG_READ if relop == 0x04 => Ok(json!({
            "field": "unread",
            "equals": !value.as_bool().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_TAG_FLAG_STATUS if relop == 0x04 => Ok(json!({
            "field": "flagged",
            "equals": value.as_i64().ok_or(EC_SEARCH_UNSUPPORTED)? == FOLLOWUP_FLAGGED as i64
        })),
        PID_TAG_HAS_ATTACHMENTS if relop == 0x04 => Ok(json!({
            "field": "hasAttachment",
            "equals": value.as_bool().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_TAG_IMPORTANCE if relop == 0x04 => Ok(json!({
            "field": "importance",
            "equals": value.as_i64().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_NAME_KEYWORDS_TAG if relop == 0x04 => Ok(json!({
            "field": "category",
            "equals": match value {
                MapiValue::String(value) => value.clone(),
                MapiValue::MultiString(values) if values.len() == 1 => values[0].clone(),
                _ => return Err(EC_SEARCH_UNSUPPORTED),
            }
        })),
        PID_TAG_SENDER_NAME_W | PID_TAG_SENDER_EMAIL_ADDRESS_W if relop == 0x04 => Ok(json!({
            "field": "sender",
            "equals": value.clone().into_text().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_TAG_SUBJECT_W | PID_TAG_NORMALIZED_SUBJECT_W if relop == 0x04 => Ok(json!({
            "field": "subject",
            "equals": value.clone().into_text().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_TAG_BODY_W | PID_TAG_BODY_STRING8 | PID_TAG_BODY_HTML_W if relop == 0x04 => Ok(json!({
            "field": "body",
            "equals": value.clone().into_text().ok_or(EC_SEARCH_UNSUPPORTED)?
        })),
        PID_TAG_CLIENT_SUBMIT_TIME | PID_TAG_MESSAGE_DELIVERY_TIME => {
            let value = filetime_to_rfc3339_utc(value.as_i64().ok_or(EC_SEARCH_UNSUPPORTED)?)
                .ok_or(EC_SEARCH_UNSUPPORTED)?;
            match relop {
                0x01 => "beforeOrAt",
                0x03 => "afterOrAt",
                0x04 => "equals",
                _ => return Err(EC_SEARCH_UNSUPPORTED),
            };
            let mut clause = serde_json::Map::new();
            clause.insert("field".to_string(), Value::String("receivedAt".to_string()));
            clause.insert(
                match relop {
                    0x01 => "beforeOrAt",
                    0x03 => "afterOrAt",
                    _ => "equals",
                }
                .to_string(),
                Value::String(value),
            );
            Ok(Value::Object(clause))
        }
        _ => Err(EC_SEARCH_UNSUPPORTED),
    }
}

fn bounded_search_criteria_to_rop(
    definition: &lpe_storage::SearchFolderDefinition,
    mailboxes: &[JmapMailbox],
    use_unicode: bool,
) -> Result<(Vec<u8>, Vec<u64>, u32), u32> {
    if definition
        .restriction_json
        .get("kind")
        .and_then(Value::as_str)
        != Some("mapi_bounded")
    {
        return Err(EC_SEARCH_UNSUPPORTED);
    }
    let clauses = definition
        .restriction_json
        .get("all")
        .and_then(Value::as_array)
        .ok_or(EC_SEARCH_UNSUPPORTED)?;
    let mut restrictions = Vec::new();
    for clause in clauses {
        restrictions.push(rop_restriction_from_json_clause(clause, use_unicode)?);
    }
    let restriction = if restrictions.is_empty() {
        Vec::new()
    } else if restrictions.len() == 1 {
        restrictions.remove(0)
    } else {
        let mut bytes = vec![0x00];
        bytes.extend_from_slice(&(restrictions.len() as u16).to_le_bytes());
        for child in restrictions {
            bytes.extend_from_slice(&child);
        }
        bytes
    };
    let mut folder_ids = Vec::new();
    if let Some(ids) = definition
        .scope_json
        .get("folderIds")
        .and_then(Value::as_array)
    {
        for id in ids {
            if let Some(id) = id.as_str().and_then(|id| uuid::Uuid::parse_str(id).ok()) {
                if let Some(mailbox) = mailboxes.iter().find(|mailbox| mailbox.id == id) {
                    if let Some(folder_id) =
                        crate::mapi::identity::mapped_mapi_object_id(&mailbox.id)
                    {
                        folder_ids.push(folder_id);
                    }
                }
            }
        }
    }
    if let Some(roles) = definition
        .scope_json
        .get("folderRoles")
        .and_then(Value::as_array)
    {
        for role in roles {
            if let Some(role) = role.as_str().and_then(folder_id_for_role) {
                folder_ids.push(role);
            }
        }
    }
    folder_ids.sort();
    folder_ids.dedup();
    let mut flags = SEARCH_RUNNING_FLAG;
    if definition
        .scope_json
        .get("recursive")
        .and_then(Value::as_bool)
        .unwrap_or(false)
    {
        flags |= SEARCH_RECURSIVE_FLAG;
    }
    Ok((restriction, folder_ids, flags))
}

fn builtin_search_criteria_to_rop(
    definition: &lpe_storage::SearchFolderDefinition,
) -> Option<(Vec<u8>, Vec<u64>, u32)> {
    if !definition.is_builtin {
        return None;
    }
    let folder_ids = builtin_search_scope_folder_ids(definition.role.as_str())?;
    Some((
        Vec::new(),
        folder_ids,
        SEARCH_RUNNING_FLAG | SEARCH_RECURSIVE_FLAG,
    ))
}

fn builtin_search_scope_folder_ids(role: &str) -> Option<Vec<u64>> {
    match role {
        "contacts_search" => Some(vec![CONTACTS_FOLDER_ID]),
        "todo_search" => Some(vec![TASKS_FOLDER_ID]),
        "reminders" => Some(vec![CALENDAR_FOLDER_ID, TASKS_FOLDER_ID]),
        "tracked_mail_processing" => Some(vec![IPM_SUBTREE_FOLDER_ID]),
        _ => None,
    }
}

fn builtin_search_role_for_folder_id(folder_id: u64) -> Option<&'static str> {
    match folder_id {
        CONTACTS_SEARCH_FOLDER_ID => Some("contacts_search"),
        TODO_SEARCH_FOLDER_ID => Some("todo_search"),
        REMINDERS_FOLDER_ID => Some("reminders"),
        TRACKED_MAIL_PROCESSING_FOLDER_ID => Some("tracked_mail_processing"),
        _ => None,
    }
}

fn builtin_search_criteria_to_rop_for_folder_id(
    folder_id: u64,
) -> Option<(Vec<u8>, Vec<u64>, u32)> {
    builtin_search_scope_folder_ids(builtin_search_role_for_folder_id(folder_id)?).map(
        |folder_ids| {
            (
                Vec::new(),
                folder_ids,
                SEARCH_RUNNING_FLAG | SEARCH_RECURSIVE_FLAG,
            )
        },
    )
}

fn rop_restriction_from_json_clause(clause: &Value, use_unicode: bool) -> Result<Vec<u8>, u32> {
    let field = clause
        .get("field")
        .and_then(Value::as_str)
        .ok_or(EC_SEARCH_UNSUPPORTED)?;
    if let Some(value) = clause.get("contains").and_then(Value::as_str) {
        return Ok(rop_content_restriction(
            property_tag_for_search_field(field, use_unicode)?,
            value,
        ));
    }
    if let Some(value) = clause.get("equals") {
        return rop_property_restriction(field, 0x04, value, use_unicode);
    }
    for (key, fuzzy_level_low) in [("notEquals", 0x0000), ("notPrefix", 0x0002)] {
        if let Some(value) = clause.get(key).and_then(Value::as_str) {
            if field != "messageClass" {
                return Err(EC_SEARCH_UNSUPPORTED);
            }
            return Ok(rop_not_content_restriction(
                string_search_property_tag(PID_TAG_MESSAGE_CLASS_W, use_unicode),
                fuzzy_level_low,
                value,
            ));
        }
    }
    for (key, relop) in [("beforeOrAt", 0x01), ("afterOrAt", 0x03)] {
        if let Some(value) = clause.get(key) {
            return rop_property_restriction(field, relop, value, use_unicode);
        }
    }
    Err(EC_SEARCH_UNSUPPORTED)
}

fn rop_content_restriction(property_tag: u32, value: &str) -> Vec<u8> {
    let mut bytes = vec![0x03];
    bytes.extend_from_slice(&0x0001u16.to_le_bytes());
    bytes.extend_from_slice(&0x0001u16.to_le_bytes());
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    write_mapi_value(
        &mut bytes,
        property_tag,
        &MapiValue::String(value.to_string()),
    );
    bytes
}

fn rop_not_content_restriction(property_tag: u32, fuzzy_level_low: u16, value: &str) -> Vec<u8> {
    let mut bytes = vec![0x02, 0x03];
    bytes.extend_from_slice(&fuzzy_level_low.to_le_bytes());
    bytes.extend_from_slice(&0x0001u16.to_le_bytes());
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    write_mapi_value(
        &mut bytes,
        property_tag,
        &MapiValue::String(value.to_string()),
    );
    bytes
}

fn rop_property_restriction(
    field: &str,
    relop: u8,
    value: &Value,
    use_unicode: bool,
) -> Result<Vec<u8>, u32> {
    let property_tag = property_tag_for_search_field(field, use_unicode)?;
    let mapi_value = match field {
        "unread" => MapiValue::Bool(!value.as_bool().ok_or(EC_SEARCH_UNSUPPORTED)?),
        "flagged" => MapiValue::U32(if value.as_bool().ok_or(EC_SEARCH_UNSUPPORTED)? {
            FOLLOWUP_FLAGGED
        } else {
            0
        }),
        "hasAttachment" => MapiValue::Bool(value.as_bool().ok_or(EC_SEARCH_UNSUPPORTED)?),
        "category" => MapiValue::MultiString(vec![value
            .as_str()
            .ok_or(EC_SEARCH_UNSUPPORTED)?
            .to_string()]),
        "receivedAt" => {
            let value = value.as_str().ok_or(EC_SEARCH_UNSUPPORTED)?;
            MapiValue::U64(mapi_mailstore::filetime_from_rfc3339_utc(value))
        }
        "importance" => MapiValue::U32(
            value
                .as_u64()
                .and_then(|value| u32::try_from(value).ok())
                .ok_or(EC_SEARCH_UNSUPPORTED)?,
        ),
        _ => MapiValue::String(value.as_str().ok_or(EC_SEARCH_UNSUPPORTED)?.to_string()),
    };
    let mut bytes = vec![0x04, relop];
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    bytes.extend_from_slice(&property_tag.to_le_bytes());
    write_mapi_value(&mut bytes, property_tag, &mapi_value);
    Ok(bytes)
}

fn property_tag_for_search_field(field: &str, use_unicode: bool) -> Result<u32, u32> {
    match field {
        "subject" => Ok(string_search_property_tag(PID_TAG_SUBJECT_W, use_unicode)),
        "body" => Ok(string_search_property_tag(PID_TAG_BODY_W, use_unicode)),
        "sender" => Ok(string_search_property_tag(
            PID_TAG_SENDER_EMAIL_ADDRESS_W,
            use_unicode,
        )),
        "category" => Ok(multiple_string_search_property_tag(
            PID_NAME_KEYWORDS_TAG,
            use_unicode,
        )),
        "unread" => Ok(PID_TAG_READ),
        "flagged" => Ok(PID_TAG_FLAG_STATUS),
        "hasAttachment" => Ok(PID_TAG_HAS_ATTACHMENTS),
        "receivedAt" => Ok(PID_TAG_MESSAGE_DELIVERY_TIME),
        "importance" => Ok(PID_TAG_IMPORTANCE),
        "messageClass" => Ok(string_search_property_tag(
            PID_TAG_MESSAGE_CLASS_W,
            use_unicode,
        )),
        _ => Err(EC_SEARCH_UNSUPPORTED),
    }
}

fn string_search_property_tag(property_tag: u32, use_unicode: bool) -> u32 {
    if use_unicode {
        property_tag
    } else {
        (property_tag & 0xFFFF_0000) | 0x001E
    }
}

fn multiple_string_search_property_tag(property_tag: u32, use_unicode: bool) -> u32 {
    if use_unicode {
        property_tag
    } else {
        (property_tag & 0xFFFF_0000) | 0x101E
    }
}

fn folder_id_for_role(role: &str) -> Option<u64> {
    match role {
        "inbox" => Some(INBOX_FOLDER_ID),
        "sent" => Some(SENT_FOLDER_ID),
        "trash" => Some(TRASH_FOLDER_ID),
        "drafts" => Some(DRAFTS_FOLDER_ID),
        "junk" => Some(JUNK_FOLDER_ID),
        "archive" => Some(ARCHIVE_FOLDER_ID),
        "outbox" => Some(OUTBOX_FOLDER_ID),
        _ => None,
    }
}

async fn hard_delete_folder_contents<S: ExchangeStore>(
    store: &S,
    principal: &AccountPrincipal,
    folder_id: u64,
    mailboxes: &[JmapMailbox],
    emails: &[JmapEmail],
    snapshot: &MapiMailStoreSnapshot,
) -> Result<(Vec<u64>, bool), u32> {
    let mailbox = role_for_folder_id(folder_id)
        .and_then(|role| mailboxes.iter().find(|mailbox| mailbox.role == role))
        .or_else(|| {
            mailboxes.iter().find(|mailbox| {
                crate::mapi::identity::mapped_mapi_object_id(&mailbox.id) == Some(folder_id)
            })
        })
        .ok_or(0x8004_010Fu32)?;

    if !snapshot
        .folder_access_for_principal(folder_id, principal.account_id)
        .map(|access| access.may_delete)
        .unwrap_or(true)
    {
        return Err(0x8007_0005);
    }

    let mut partial_completion = false;
    let mut changed_folder_ids = Vec::new();
    let message_ids = emails
        .iter()
        .filter(|email| email_matches_folder(email, folder_id, mailboxes))
        .map(|email| email.id)
        .collect::<Vec<_>>();
    let attempted_count = message_ids.len();
    let mut succeeded_count = 0usize;
    let mut failed_count = 0usize;

    for message_id in message_ids {
        if store
            .delete_jmap_email_from_mailbox(
                principal.account_id,
                mailbox.id,
                message_id,
                AuditEntryInput {
                    actor: principal.email.clone(),
                    action: "mapi-hard-delete-folder-contents".to_string(),
                    subject: format!("folder:{} message:{}", mailbox.id, message_id),
                },
            )
            .await
            .is_err()
        {
            partial_completion = true;
            failed_count += 1;
        } else {
            if changed_folder_ids.is_empty() {
                changed_folder_ids.push(folder_id);
            }
            succeeded_count += 1;
        }
    }
    tracing::info!(
        rca_debug = true,
        adapter = "mapi",
        mailbox = %principal.email,
        folder_id = %format!("{folder_id:#018x}"),
        folder_role = debug_role_for_folder_id(folder_id),
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
        message = "rca debug mapi hard delete folder contents"
    );
    record_mapi_folder_purge_metrics(
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
    );
    Ok((changed_folder_ids, partial_completion))
}

async fn hard_delete_public_folder_contents<S: ExchangeStore>(
    store: &S,
    principal: &AccountPrincipal,
    folder_id: u64,
    snapshot: &MapiMailStoreSnapshot,
) -> Result<(Vec<u64>, bool), u32> {
    let Some(folder) = snapshot.public_folder_for_id(folder_id) else {
        return Err(0x8004_010F);
    };
    let item_ids = snapshot
        .public_folder_items_for_folder(folder_id)
        .into_iter()
        .map(|item| item.item.id)
        .collect::<Vec<_>>();
    let attempted_count = item_ids.len();
    let mut succeeded_count = 0usize;
    let mut failed_count = 0usize;
    let mut partial_completion = false;

    for item_id in item_ids {
        if store
            .delete_public_folder_item(
                principal.account_id,
                folder.folder.id,
                item_id,
                AuditEntryInput {
                    actor: principal.email.clone(),
                    action: "mapi-hard-delete-public-folder-contents".to_string(),
                    subject: format!("public-folder:{} item:{}", folder.folder.id, item_id),
                },
            )
            .await
            .is_err()
        {
            partial_completion = true;
            failed_count += 1;
        } else {
            succeeded_count += 1;
        }
    }

    tracing::info!(
        rca_debug = true,
        adapter = "mapi",
        mailbox = %principal.email,
        folder_id = %format!("{folder_id:#018x}"),
        public_folder_id = %folder.folder.id,
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
        message = "rca debug mapi hard delete public folder contents"
    );
    record_mapi_folder_purge_metrics(
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
    );
    Ok(if succeeded_count == 0 {
        (Vec::new(), partial_completion)
    } else {
        (vec![folder_id], partial_completion)
    })
}

async fn hard_delete_mailbox_tree_contents<S: ExchangeStore>(
    store: &S,
    principal: &AccountPrincipal,
    folder_id: u64,
    mailboxes: &[JmapMailbox],
    emails: &[JmapEmail],
    snapshot: &MapiMailStoreSnapshot,
) -> Result<(Vec<u64>, bool), u32> {
    let root_mailbox = role_for_folder_id(folder_id)
        .and_then(|role| mailboxes.iter().find(|mailbox| mailbox.role == role))
        .or_else(|| {
            mailboxes.iter().find(|mailbox| {
                crate::mapi::identity::mapped_mapi_object_id(&mailbox.id) == Some(folder_id)
            })
        })
        .ok_or(0x8004_010Fu32)?;

    let mut target_mailboxes = Vec::new();
    for mailbox in mailboxes {
        let mut current = Some(mailbox.id);
        let mut visited = HashSet::new();
        while let Some(current_id) = current {
            if current_id == root_mailbox.id {
                target_mailboxes.push(mailbox);
                break;
            }
            if !visited.insert(current_id) {
                break;
            }
            current = mailboxes
                .iter()
                .find(|candidate| candidate.id == current_id)
                .and_then(|candidate| candidate.parent_id);
        }
    }

    let target_folder_ids = target_mailboxes
        .iter()
        .map(|mailbox| {
            (
                crate::mapi::identity::mapped_mapi_object_id(&mailbox.id)
                    .unwrap_or_else(|| mapi_folder_id(mailbox)),
                mailbox.id,
            )
        })
        .collect::<Vec<_>>();

    for (target_folder_id, _) in &target_folder_ids {
        if !snapshot
            .folder_access_for_principal(*target_folder_id, principal.account_id)
            .map(|access| access.may_delete)
            .unwrap_or(true)
        {
            return Err(0x8007_0005);
        }
    }

    let mut partial_completion = false;
    let mut changed_folder_ids = Vec::new();
    let mut attempted_count = 0usize;
    let mut succeeded_count = 0usize;
    let mut failed_count = 0usize;
    for (target_folder_id, mailbox_id) in target_folder_ids {
        let message_ids = emails
            .iter()
            .filter(|email| email_matches_folder(email, target_folder_id, mailboxes))
            .map(|email| email.id)
            .collect::<Vec<_>>();
        attempted_count += message_ids.len();
        for message_id in message_ids {
            if store
                .delete_jmap_email_from_mailbox(
                    principal.account_id,
                    mailbox_id,
                    message_id,
                    AuditEntryInput {
                        actor: principal.email.clone(),
                        action: "mapi-hard-delete-folder-tree-contents".to_string(),
                        subject: format!("folder:{mailbox_id} message:{message_id}"),
                    },
                )
                .await
                .is_err()
            {
                partial_completion = true;
                failed_count += 1;
            } else {
                if !changed_folder_ids.contains(&target_folder_id) {
                    changed_folder_ids.push(target_folder_id);
                }
                succeeded_count += 1;
            }
        }
    }
    tracing::debug!(
        rca_debug = true,
        adapter = "mapi",
        mailbox = %principal.email,
        folder_id = %format!("{folder_id:#018x}"),
        folder_role = debug_role_for_folder_id(folder_id),
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
        message = "rca debug mapi hard delete folder tree contents"
    );
    record_mapi_folder_purge_metrics(
        attempted_count,
        succeeded_count,
        failed_count,
        partial_completion,
    );
    Ok((changed_folder_ids, partial_completion))
}

async fn hard_delete_recoverable_folder_contents<S: ExchangeStore>(
    store: &S,
    principal: &AccountPrincipal,
    folder_id: u64,
    snapshot: &MapiMailStoreSnapshot,
) -> Result<(Vec<u64>, bool), u32> {
    let items = snapshot.recoverable_items_for_folder(folder_id);
    if crate::mapi_store::recoverable_storage_folder(folder_id).is_none() {
        return Err(0x8004_010F);
    }
    let mut partial_completion = false;
    let mut changed_folder_ids = Vec::new();
    for item in items {
        if store
            .purge_recoverable_item(
                principal.account_id,
                item.canonical_id,
                AuditEntryInput {
                    actor: principal.email.clone(),
                    action: "mapi-empty-recoverable-folder".to_string(),
                    subject: format!("recoverable:{}", item.canonical_id),
                },
            )
            .await
            .is_err()
        {
            partial_completion = true;
        } else {
            if changed_folder_ids.is_empty() {
                changed_folder_ids.push(folder_id);
            }
        }
    }
    Ok((changed_folder_ids, partial_completion))
}

async fn acquire_execute_active_session_request(session_id: &str) -> Option<ActiveSessionRequest> {
    for attempt in 0..EXECUTE_ACTIVE_SESSION_RETRY_ATTEMPTS {
        if let Some(active_request) = begin_active_session_request(session_id) {
            return Some(active_request);
        }
        if attempt + 1 < EXECUTE_ACTIVE_SESSION_RETRY_ATTEMPTS {
            tokio::time::sleep(std::time::Duration::from_millis(
                EXECUTE_ACTIVE_SESSION_RETRY_DELAY_MS,
            ))
            .await;
        }
    }
    None
}

pub(in crate::mapi) async fn execute_response<S, V>(
    store: &S,
    validator: &Validator<V>,
    endpoint: MapiEndpoint,
    principal: &AccountPrincipal,
    headers: &HeaderMap,
    body: &[u8],
    request_id: &str,
) -> Response
where
    S: ExchangeStore,
    V: Detector,
{
    log_session_cookie_lookup(endpoint, principal, headers, "Execute");
    let Some(session_id) = request_cookie(endpoint, headers) else {
        return execute_failure_response(request_id, 13, "missing MAPI session cookie", None);
    };
    if !request_sequence_cookie_matches(endpoint, headers, &session_id) {
        return execute_failure_response(
            request_id,
            6,
            "invalid MAPI request sequence cookie",
            None,
        );
    }
    let Some(_active_request) = acquire_execute_active_session_request(&session_id).await else {
        return execute_failure_response(
            request_id,
            15,
            "MAPI session already has an active request",
            None,
        );
    };
    let Some(mut session) = get_session(&session_id) else {
        return execute_failure_response(request_id, 10, "MAPI session context not found", None);
    };
    if session.endpoint != endpoint
        || session.tenant_id != principal.tenant_id
        || session.account_id != principal.account_id
        || session.email != principal.email
    {
        return execute_failure_response(
            request_id,
            10,
            "MAPI authentication context changed",
            None,
        );
    }
    session.record_transport_request("Execute", request_id);

    let execute = match parse_execute_request(body) {
        Ok(execute) => execute,
        Err(error) => {
            log_execute_parse_failure_debug(endpoint, principal, headers, request_id, body, &error);
            return execute_failure_response(
                request_id,
                4,
                &format!("invalid Execute request body: {error}"),
                Some(session_cookie(endpoint, &session_id, false)),
            );
        }
    };
    if !session_matches(&session, endpoint, principal) {
        return execute_failure_response(
            request_id,
            10,
            "MAPI authentication context changed",
            Some(session_cookie(endpoint, &session_id, false)),
        );
    }
    let rop_fingerprint = mapi_payload_fingerprint(&execute.rop_buffer);
    let request_debug = summarize_request_rop_buffer(&execute.rop_buffer);
    log_execute_request_start_debug(
        endpoint,
        principal,
        headers,
        request_id,
        body.len(),
        &execute.rop_buffer,
        &request_debug,
    );
    let hierarchy_completed_before_execute = session.hierarchy_sync_completed();
    if let Some(cached) = session.completed_execute_requests.get(request_id).cloned() {
        if cached.rop_fingerprint == rop_fingerprint {
            let post_hierarchy_observation =
                if endpoint == MapiEndpoint::Emsmdb && hierarchy_completed_before_execute {
                    session.record_execute_after_hierarchy_completion(&request_debug.ids)
                } else {
                    PostHierarchyExecuteObservation::default()
                };
            let cached_rop_buffer = execute_success_rop_buffer(&cached.response_body);
            log_execute_rop_debug(
                endpoint,
                principal,
                headers,
                &session_id,
                request_id,
                &request_debug,
                &execute.rop_buffer,
                cached_rop_buffer.unwrap_or_default(),
                &session,
                post_hierarchy_observation,
            );
            store_session(session_id.clone(), session);
            return mapi_response_with_cookies(
                "Execute",
                request_id,
                0,
                cached.response_body,
                session_context_cookies(endpoint, &session_id, false),
            );
        }
        store_session(session_id.clone(), session);
        return execute_failure_response(
            request_id,
            12,
            "reused MAPI Execute request id with a different ROP payload",
            Some(session_cookie(endpoint, &session_id, false)),
        );
    }

    if rop_buffer_has_no_requests(&execute.rop_buffer)
        || rop_buffer_is_store_independent_logon(&execute.rop_buffer)
        || rop_buffer_is_store_independent_release_only(&execute.rop_buffer)
        || rop_buffer_is_store_independent_special_folder_getprops_probe(
            &execute.rop_buffer,
            &session,
        )
    {
        let snapshot = MapiMailStoreSnapshot::empty();
        let mailboxes = snapshot.mailboxes();
        let emails = snapshot.emails();
        log_execute_dispatch_start_debug(
            endpoint,
            principal,
            headers,
            request_id,
            mailboxes.len(),
            emails.len(),
        );
        let rop_buffer = execute_rops(
            store,
            principal,
            request_id,
            &mut session,
            &mailboxes,
            &emails,
            &snapshot,
            validator,
            &execute.rop_buffer,
            request_debug.all_release,
            request_debug.handle_count,
            &request_debug.handle_table_summary,
            &request_debug.ids_csv,
            &request_debug.names_csv,
            &request_debug.non_release_rops,
        )
        .await;
        let post_hierarchy_observation =
            if endpoint == MapiEndpoint::Emsmdb && hierarchy_completed_before_execute {
                session.record_execute_after_hierarchy_completion(&request_debug.ids)
            } else {
                PostHierarchyExecuteObservation::default()
            };
        log_execute_rop_debug(
            endpoint,
            principal,
            headers,
            &session_id,
            request_id,
            &request_debug,
            &execute.rop_buffer,
            &rop_buffer,
            &session,
            post_hierarchy_observation,
        );
        let rop_buffer = apply_execute_max_rop_out(
            request_id,
            &execute.rop_buffer,
            rop_buffer,
            execute.max_rop_out,
        );
        let response_body = execute_success_body(rop_buffer, Vec::new());
        let response_debug = summarize_response_rop_buffer(
            execute_success_rop_buffer(&response_body).unwrap_or_default(),
            &request_debug.ids,
        );
        cache_execute_response(
            &mut session,
            request_id,
            rop_fingerprint,
            &response_body,
            request_debug.ids_csv.clone(),
            response_debug.ids_csv,
            response_debug.results_csv,
            response_debug.response_payload_bytes,
        );
        store_session(session_id.clone(), session);
        return mapi_response_with_cookies(
            "Execute",
            request_id,
            0,
            response_body,
            session_context_cookies(endpoint, &session_id, false),
        );
    }

    let access_plan = plan_mapi_store_access(&session, &execute.rop_buffer);
    log_execute_store_access_debug(endpoint, principal, headers, request_id, &access_plan);
    let snapshot = match load_mapi_store_for_access_plan(
        store,
        principal.account_id,
        &access_plan,
        500,
    )
    .await
    {
        Ok(snapshot) => snapshot,
        Err(error) => {
            if let Some(fallback_plan) = hierarchy_sync_selective_fallback_plan(&execute.rop_buffer)
            {
                tracing::warn!(
                    rca_debug = true,
                    adapter = "mapi",
                    endpoint = "emsmdb",
                    tenant_id = %principal.tenant_id,
                    account_id = %principal.account_id,
                    mailbox = %principal.email,
                    request_type = "Execute",
                    mapi_request_id = request_id,
                    full_snapshot_error = %format!("{error:#}"),
                    "rca debug mapi full snapshot fallback to hierarchy store view"
                );
                match load_mapi_store_for_access_plan(
                    store,
                    principal.account_id,
                    &fallback_plan,
                    500,
                )
                .await
                {
                    Ok(snapshot) => snapshot,
                    Err(fallback_error) => {
                        store_session(session_id.clone(), session);
                        return execute_failure_response(
                            request_id,
                            4,
                            &format!(
                                "failed to load MAPI mail store view: {error:#}; fallback failed: {fallback_error:#}"
                            ),
                            Some(session_cookie(endpoint, &session_id, false)),
                        );
                    }
                }
            } else {
                store_session(session_id.clone(), session);
                return execute_failure_response(
                    request_id,
                    4,
                    &format!("failed to load MAPI mail store view: {error:#}"),
                    Some(session_cookie(endpoint, &session_id, false)),
                );
            }
        }
    };
    let mailboxes = snapshot.mailboxes();
    let emails = snapshot.emails();
    log_execute_dispatch_start_debug(
        endpoint,
        principal,
        headers,
        request_id,
        mailboxes.len(),
        emails.len(),
    );
    let rop_buffer = execute_rops(
        store,
        principal,
        request_id,
        &mut session,
        &mailboxes,
        &emails,
        &snapshot,
        validator,
        &execute.rop_buffer,
        request_debug.all_release,
        request_debug.handle_count,
        &request_debug.handle_table_summary,
        &request_debug.ids_csv,
        &request_debug.names_csv,
        &request_debug.non_release_rops,
    )
    .await;
    let post_hierarchy_observation =
        if endpoint == MapiEndpoint::Emsmdb && hierarchy_completed_before_execute {
            session.record_execute_after_hierarchy_completion(&request_debug.ids)
        } else {
            PostHierarchyExecuteObservation::default()
        };
    log_execute_rop_debug(
        endpoint,
        principal,
        headers,
        &session_id,
        request_id,
        &request_debug,
        &execute.rop_buffer,
        &rop_buffer,
        &session,
        post_hierarchy_observation,
    );
    let rop_buffer = apply_execute_max_rop_out(
        request_id,
        &execute.rop_buffer,
        rop_buffer,
        execute.max_rop_out,
    );
    let response_body = execute_success_body(rop_buffer, Vec::new());
    let response_debug = summarize_response_rop_buffer(
        execute_success_rop_buffer(&response_body).unwrap_or_default(),
        &request_debug.ids,
    );
    cache_execute_response(
        &mut session,
        request_id,
        rop_fingerprint,
        &response_body,
        request_debug.ids_csv.clone(),
        response_debug.ids_csv,
        response_debug.results_csv,
        response_debug.response_payload_bytes,
    );
    store_session(session_id.clone(), session);
    mapi_response_with_cookies(
        "Execute",
        request_id,
        0,
        response_body,
        session_context_cookies(endpoint, &session_id, false),
    )
}

pub(in crate::mapi) struct ExecuteRequest {
    rop_buffer: Vec<u8>,
    max_rop_out: u32,
}

pub(in crate::mapi) fn parse_execute_request(body: &[u8]) -> Result<ExecuteRequest> {
    let mut cursor = Cursor::new(body);
    let _flags = cursor.read_u32()?;
    let rop_buffer_size = cursor.read_u32()? as usize;
    let rop_buffer = cursor.read_bytes(rop_buffer_size)?.to_vec();
    let max_rop_out = cursor.read_u32()?;
    let auxiliary_buffer_size = cursor.read_u32()? as usize;
    let _auxiliary_buffer = cursor.read_bytes(auxiliary_buffer_size)?;
    Ok(ExecuteRequest {
        rop_buffer,
        max_rop_out,
    })
}

fn log_execute_parse_failure_debug(
    endpoint: MapiEndpoint,
    principal: &AccountPrincipal,
    headers: &HeaderMap,
    request_id: &str,
    body: &[u8],
    error: &anyhow::Error,
) {
    let client_request_id = safe_header(headers, "client-request-id").unwrap_or_default();
    let client_application = safe_header(headers, "x-clientapplication").unwrap_or_default();
    let client_info = safe_header(headers, "x-clientinfo").unwrap_or_default();
    let trace_id = safe_header(headers, "x-trace-id").unwrap_or_default();
    let endpoint = match endpoint {
        MapiEndpoint::Emsmdb => "emsmdb",
        MapiEndpoint::Nspi => "nspi",
    };
    let flags = read_le_u32_at(body, 0);
    let rop_buffer_size = read_le_u32_at(body, 4);
    let rop_buffer_end = rop_buffer_size.and_then(|size| 8usize.checked_add(size as usize));
    let max_rop_out = rop_buffer_end.and_then(|offset| read_le_u32_at(body, offset));
    let auxiliary_buffer_size =
        rop_buffer_end.and_then(|offset| read_le_u32_at(body, offset.saturating_add(4)));
    let expected_body_bytes = match (rop_buffer_end, auxiliary_buffer_size) {
        (Some(offset), Some(auxiliary_buffer_size)) => offset
            .checked_add(8)
            .and_then(|offset| offset.checked_add(auxiliary_buffer_size as usize)),
        _ => None,
    };
    tracing::warn!(
        rca_debug = true,
        adapter = "mapi",
        endpoint = endpoint,
        tenant_id = %principal.tenant_id,
        account_id = %principal.account_id,
        mailbox = %principal.email,
        request_type = "Execute",
        mapi_request_id = request_id,
        client_request_id = %client_request_id,
        client_application = %client_application,
        client_info = %client_info,
        trace_id = %trace_id,
        request_body_bytes = body.len(),
        execute_flags = flags.map(format_hex_u32).unwrap_or_default(),
        declared_rop_buffer_size = rop_buffer_size
            .map(|value| value.to_string())
            .unwrap_or_default(),
        max_rop_out = max_rop_out.map(|value| value.to_string()).unwrap_or_default(),
        declared_auxiliary_buffer_size = auxiliary_buffer_size
            .map(|value| value.to_string())
            .unwrap_or_default(),
        expected_body_bytes = expected_body_bytes
            .map(|value| value.to_string())
            .unwrap_or_default(),
        body_preview_hex = %debug_payload_preview_hex(body),
        parse_error = %error,
        "rca debug mapi execute parse failure"
    );
}

fn read_le_u32_at(bytes: &[u8], offset: usize) -> Option<u32> {
    let value = bytes.get(offset..offset.checked_add(4)?)?;
    Some(u32::from_le_bytes(value.try_into().ok()?))
}

fn format_hex_u32(value: u32) -> String {
    format!("0x{value:08x}")
}

fn apply_execute_max_rop_out(
    request_id: &str,
    request_rop_buffer: &[u8],
    response_rop_buffer: Vec<u8>,
    max_rop_out: u32,
) -> Vec<u8> {
    if max_rop_out == 0 || response_rop_buffer.len() <= max_rop_out as usize {
        return response_rop_buffer;
    }
    let Some((requests, handle_table)) = split_rop_buffer(request_rop_buffer) else {
        return response_rop_buffer;
    };
    let replacement =
        rop_buffer_too_small_response(response_rop_buffer.len(), requests, handle_table);
    tracing::info!(
        rca_debug = true,
        adapter = "mapi",
        endpoint = "emsmdb",
        request_type = "Execute",
        mapi_request_id = request_id,
        max_rop_out,
        response_rop_buffer_size = response_rop_buffer.len(),
        replacement_rop_buffer_size = replacement.len(),
        "rca debug mapi execute max rop out exceeded"
    );
    replacement
}

fn rop_buffer_is_store_independent_logon(rop_buffer: &[u8]) -> bool {
    let Some((requests, _handle_table)) = split_rop_buffer(rop_buffer) else {
        return false;
    };
    let mut cursor = Cursor::new(requests);
    let mut saw_request = false;
    while cursor.remaining() > 0 {
        let Ok(request) = read_rop_request(&mut cursor) else {
            return false;
        };
        if !matches!(RopId::from_u8(request.rop_id), Some(RopId::Logon)) {
            return false;
        }
        saw_request = true;
    }
    saw_request
}

fn rop_buffer_is_store_independent_release_only(rop_buffer: &[u8]) -> bool {
    let Some((requests, _handle_table)) = split_rop_buffer(rop_buffer) else {
        return false;
    };
    let mut cursor = Cursor::new(requests);
    let mut saw_request = false;
    while cursor.remaining() > 0 {
        let Ok(request) = read_rop_request(&mut cursor) else {
            return false;
        };
        if !matches!(RopId::from_u8(request.rop_id), Some(RopId::Release)) {
            return false;
        }
        saw_request = true;
    }
    saw_request
}

fn rop_buffer_is_store_independent_special_folder_getprops_probe(
    rop_buffer: &[u8],
    session: &MapiSession,
) -> bool {
    let Some((requests, handle_table)) = split_rop_buffer(rop_buffer) else {
        return false;
    };
    let Ok(handle_slots) = read_handle_table(handle_table) else {
        return false;
    };
    let mut opened_probe_folder_by_index = HashMap::new();
    let mut saw_open_folder = false;
    let mut saw_get_properties = false;
    let mut cursor = Cursor::new(requests);
    while cursor.remaining() > 0 {
        let Ok(request) = read_rop_request(&mut cursor) else {
            return false;
        };
        match RopId::from_u8(request.rop_id) {
            Some(RopId::Release) => {}
            Some(RopId::OpenFolder) => {
                let folder_id = session
                    .resolve_special_folder_alias(request.folder_id().unwrap_or(ROOT_FOLDER_ID));
                if !is_store_independent_special_folder(folder_id) {
                    return false;
                }
                opened_probe_folder_by_index
                    .insert(request.output_handle_index.unwrap_or(0), folder_id);
                saw_open_folder = true;
            }
            Some(RopId::GetPropertiesSpecific) => {
                let property_tags = request.property_tags();
                if property_tags.iter().copied().any(is_custom_property_tag) {
                    return false;
                }
                let input_handle_index = request.input_handle_index().unwrap_or(0);
                let opened_folder_id = opened_probe_folder_by_index
                    .get(&input_handle_index)
                    .copied();
                let existing_folder_id = input_handle(&handle_slots, &request)
                    .and_then(|handle| session.handles.get(&handle))
                    .and_then(MapiObject::folder_id);
                let Some(folder_id) = opened_folder_id.or(existing_folder_id) else {
                    return false;
                };
                if !is_store_independent_folder_getprops_probe(folder_id, &property_tags) {
                    return false;
                }
                saw_get_properties = true;
            }
            _ => return false,
        }
    }
    saw_open_folder && saw_get_properties
}

fn is_store_independent_folder_getprops_probe(folder_id: u64, property_tags: &[u32]) -> bool {
    is_store_independent_special_folder(folder_id)
        && !property_tags
            .iter()
            .any(|tag| strips_default_folder_identification_value_for_folder_id(folder_id, *tag))
}

fn is_store_independent_special_folder(folder_id: u64) -> bool {
    matches!(
        folder_id,
        ROOT_FOLDER_ID
            | COMMON_VIEWS_FOLDER_ID
            | SCHEDULE_FOLDER_ID
            | SEARCH_FOLDER_ID
            | VIEWS_FOLDER_ID
            | SHORTCUTS_FOLDER_ID
            | FREEBUSY_DATA_FOLDER_ID
    )
}

fn rop_buffer_has_no_requests(rop_buffer: &[u8]) -> bool {
    split_rop_buffer(rop_buffer)
        .map(|(requests, _handle_table)| requests.is_empty())
        .unwrap_or(false)
}

fn execute_success_rop_buffer(body: &[u8]) -> Option<&[u8]> {
    let mut cursor = Cursor::new(body);
    cursor.read_u32().ok()?;
    cursor.read_u32().ok()?;
    cursor.read_u32().ok()?;
    let rop_buffer_size = cursor.read_u32().ok()? as usize;
    cursor.read_bytes(rop_buffer_size).ok()
}

